import type { Metadata } from "next"
import type { ReactNode } from "react"
import Providers from "./providers"
import "./globals.css"

export const metadata: Metadata = {
  title: "Falcon-512 | Post-Quantum Signatures on Starknet",
  description:
    "Demo of Falcon-512 post-quantum signature verification for Starknet account abstraction. 63K steps, 62 calldata felts.",
}

export default function RootLayout({ children }: { readonly children: ReactNode }) {
  return (
    <html lang="en" className="dark">
      <body className="bg-falcon-bg text-falcon-text antialiased">
        <Providers>{children}</Providers>
      </body>
    </html>
  )
}

"use client"

/**
 * VerificationPlayground — interactive Falcon-512 signature demo.
 *
 * Lets the user:
 *   1. Generate a Falcon-512 keypair in-browser via WASM
 *   2. Type a message to sign
 *   3. Run sign + verify and see the result with timing
 *
 * Architecture:
 * - Atom state (keypairAtom, verificationStepAtom, messageAtom, etc.) drives
 *   all UI updates — no local useState.
 * - FalconService methods are run via a ManagedRuntime (singleton defined
 *   outside the component) so the WASM layer is loaded at most once.
 * - All Option values are handled via Option.match (never getOrThrow).
 * - Hex display uses bytesToHex (browser-safe, no Buffer.from).
 */

import React, { useCallback } from "react"
import { Cause, Exit, Layer, ManagedRuntime, Option } from "effect"
import { useAtomValue, useAtomSet } from "@effect-atom/atom-react"
import { FalconService } from "@/services/FalconService"
import { WasmRuntimeLive } from "@/services/WasmRuntime"
import {
  keypairAtom,
  messageAtom,
  signatureAtom,
  verificationStepAtom,
  wasmStatusAtom,
} from "@/atoms/falcon"
import { HexDisplay } from "./HexDisplay"
import { bytesToHex, getVerificationDisabledState } from "./verification-utils"

// ─── Service runtime (singleton — WASM loaded lazily, at most once) ──────────

const appRuntime = ManagedRuntime.make(
  FalconService.Default.pipe(Layer.provide(WasmRuntimeLive)),
)
// Intentionally process-lifetime scoped for SPA usage; disposing would drop
// loaded WASM state and force a reload with no functional benefit here.

// ─── Component ────────────────────────────────────────────────────────────────

export function VerificationPlayground(): React.JSX.Element {
  // ── Atom reads ──────────────────────────────────────────────────────────
  const message = useAtomValue(messageAtom)
  const keypair = useAtomValue(keypairAtom)
  const step = useAtomValue(verificationStepAtom)

  // ── Atom writes ─────────────────────────────────────────────────────────
  const setMessage = useAtomSet(messageAtom)
  const setKeypair = useAtomSet(keypairAtom)
  const setStep = useAtomSet(verificationStepAtom)
  const setSignature = useAtomSet(signatureAtom)
  const setWasmStatus = useAtomSet(wasmStatusAtom)

  // ── Derived disabled state ───────────────────────────────────────────────
  const { isBusy, canGenerate, canSign } = getVerificationDisabledState({
    keypair,
    message,
    step,
  })

  // ── Handler: Generate Keypair ────────────────────────────────────────────
  const handleGenerateKeypair = useCallback(async () => {
    setStep({ step: "generating-keypair" })
    const seed = crypto.getRandomValues(new Uint8Array(32))

    const exit = await appRuntime.runPromiseExit(
      FalconService.generateKeypair(seed),
    )

    if (Exit.isSuccess(exit)) {
      setKeypair(Option.some(exit.value))
      setWasmStatus("ready")
      setStep({ step: "idle" })
    } else {
      const errOpt = Cause.failureOption(exit.cause)
      const msg = Option.match(errOpt, {
        onNone: () => "Keypair generation failed",
        onSome: (e) => e.message,
      })
      setStep({ step: "error", message: msg })
    }
  }, [setKeypair, setStep, setWasmStatus])

  // ── Handler: Sign & Verify ───────────────────────────────────────────────
  const handleSignAndVerify = useCallback(async () => {
    // Extract keypair via Option.match — never getOrThrow
    const kp = Option.match(keypair, {
      onNone: () => null,
      onSome: (k) => k,
    })
    if (!kp) return

    const startTime = Date.now()
    const messageBytes = new TextEncoder().encode(message)

    // ── Sign ──────────────────────────────────────────────────────────────
    setStep({ step: "signing" })
    const signExit = await appRuntime.runPromiseExit(
      FalconService.sign(kp.secretKey, messageBytes),
    )

    if (Exit.isFailure(signExit)) {
      const errOpt = Cause.failureOption(signExit.cause)
      const msg = Option.match(errOpt, {
        onNone: () => "Signing failed",
        onSome: (e) => e.message,
      })
      setStep({ step: "error", message: msg })
      return
    }

    const sigResult = signExit.value
    setSignature(Option.some(sigResult))

    // ── Verify ────────────────────────────────────────────────────────────
    setStep({ step: "verifying", substep: "verify" })
    const verifyExit = await appRuntime.runPromiseExit(
      FalconService.verify(kp.verifyingKey, messageBytes, sigResult.signature),
    )

    if (Exit.isFailure(verifyExit)) {
      const errOpt = Cause.failureOption(verifyExit.cause)
      const msg = Option.match(errOpt, {
        onNone: () => "Verification failed",
        onSome: (e) => e.message,
      })
      setStep({ step: "error", message: msg })
      return
    }

    const durationMs = Date.now() - startTime
    setStep({ step: "complete", valid: verifyExit.value, durationMs })
  }, [keypair, message, setSignature, setStep])

  // ── Derived display values ───────────────────────────────────────────────
  // Use bytesToHex (browser-safe, no Buffer.from) + Option.match (no getOrThrow)
  const keypairHexPreview = Option.match(keypair, {
    onNone: () => null,
    onSome: (kp) => "0x" + bytesToHex(kp.verifyingKey),
  })

  // ── Render ───────────────────────────────────────────────────────────────
  return (
    <section id="verify" className="px-6 py-20 lg:px-8">
      <div className="mx-auto max-w-4xl">
        {/* Section header */}
        <h2 className="text-3xl font-bold tracking-tight text-falcon-text">
          Verification Playground
        </h2>
        <p className="mt-4 text-falcon-muted">
          Generate a Falcon-512 keypair in-browser via WASM, sign a message,
          and verify the signature. All crypto runs locally — no server
          involvement.
        </p>

        <div className="mt-8 space-y-6">
          {/* Message input */}
          <div>
            <label
              htmlFor="message-input"
              className="block text-sm font-medium text-falcon-text"
            >
              Message
            </label>
            <input
              id="message-input"
              type="text"
              value={message}
              onChange={(e) => setMessage(e.target.value)}
              disabled={isBusy}
              placeholder="Enter a message to sign…"
              className="mt-1 w-full rounded-lg border border-falcon-muted/30 bg-falcon-surface px-4 py-2 font-mono text-sm text-falcon-text placeholder-falcon-muted focus:outline-none focus:ring-2 focus:ring-falcon-primary disabled:cursor-not-allowed disabled:opacity-50"
            />
          </div>

          {/* Action buttons */}
          <div className="flex flex-wrap gap-4">
            <button
              onClick={handleGenerateKeypair}
              aria-label="Generate Keypair"
              disabled={!canGenerate}
              className="rounded-lg bg-falcon-primary px-6 py-2.5 text-sm font-semibold text-falcon-text transition-opacity hover:opacity-90 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-falcon-primary disabled:cursor-not-allowed disabled:opacity-50"
            >
              {step.step === "generating-keypair"
                ? "Generating..."
                : "Generate Keypair"}
            </button>

            <button
              onClick={handleSignAndVerify}
              aria-label="Sign and verify message"
              disabled={!canSign}
              className="rounded-lg bg-falcon-accent px-6 py-2.5 text-sm font-semibold text-falcon-text transition-opacity hover:opacity-90 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-falcon-accent disabled:cursor-not-allowed disabled:opacity-50"
            >
              {step.step === "signing" || step.step === "verifying"
                ? "Running…"
                : "Sign & Verify"}
            </button>
          </div>

          {/* Keypair hex preview — uses bytesToHex, no Buffer.from */}
          {keypairHexPreview !== null && (
            <HexDisplay
              label="Verifying Key (preview)"
              value={keypairHexPreview}
              truncate={{ head: 18, tail: 8 }}
            />
          )}

          {/* Success result */}
          {step.step === "complete" && (
            <div
              role="status"
              aria-live="polite"
              className={`rounded-xl border p-4 ${
                step.valid
                  ? "border-falcon-success/30 bg-falcon-success/10"
                  : "border-falcon-error/30 bg-falcon-error/10"
              }`}
            >
              <div className="flex items-center gap-3">
                <span
                  className={`text-xl font-bold ${
                    step.valid ? "text-falcon-success" : "text-falcon-error"
                  }`}
                >
                  {step.valid ? "✓" : "✗"}
                </span>
                <span className="font-semibold text-falcon-text">
                  {step.valid ? "Signature valid" : "Signature invalid"}
                </span>
                <span className="ml-auto text-sm text-falcon-muted">
                  {step.durationMs}ms
                </span>
              </div>
            </div>
          )}

          {/* Error state */}
          {step.step === "error" && (
            <div
              role="alert"
              aria-live="polite"
              className="rounded-xl border border-falcon-error/30 bg-falcon-error/10 p-4"
            >
              <div className="flex items-start gap-3">
                <span className="text-xl font-bold text-falcon-error">✗</span>
                <div className="flex-1">
                  <p className="font-semibold text-falcon-error">Error</p>
                  <p className="mt-1 break-all text-sm text-falcon-muted">
                    {step.message}
                  </p>
                </div>
                <button
                  onClick={() => setStep({ step: "idle" })}
                  aria-label="Reset verification state"
                  className="ml-auto rounded-lg border border-falcon-muted/30 px-3 py-1 text-xs text-falcon-muted hover:bg-falcon-surface"
                >
                  Try Again
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </section>
  )
}

import { Effect } from "effect"
import { WasmRuntime } from "./WasmRuntime"
import {
  KeygenError,
  SigningError,
  HintGenerationError,
  PackingError,
  VerificationError,
} from "./errors"
import type {
  FalconKeypair,
  FalconSignatureResult,
  PackedPublicKey,
} from "./types"

// ---------------------------------------------------------------------------
// VK byte deserialization
// ---------------------------------------------------------------------------

/**
 * Deserialize a Falcon-512 verifying key (896 bytes) into 512 NTT-domain
 * coefficients stored as an Int32Array.
 *
 * Format (falcon-rs, PUBLIC_KEY_LEN = 896, no header):
 *   - 512 coefficients x 14 bits each, packed LSB-first
 *
 * Algorithm: maintains a bit-buffer, loading bytes from the input one at a
 * time and extracting 14-bit windows.
 *
 * Throws on invalid input (too few bytes, or any coefficient >= Q=12289).
 */
function parsePublicKeyNttBytes(vkBytes: Uint8Array): Int32Array {
  const Q = 12289
  const N = 512
  const BITS_PER_COEFF = 14
  const DATA_BYTES = (N * BITS_PER_COEFF) / 8 // 896

  if (vkBytes.length < DATA_BYTES) {
    throw new Error(
      `VK too short: expected at least ${DATA_BYTES} bytes, got ${vkBytes.length}`,
    )
  }

  const coeffs = new Int32Array(N)
  const mask = (1 << BITS_PER_COEFF) - 1 // 0x3FFF

  let bitBuffer = 0
  let bitsInBuffer = 0
  let byteIndex = 0

  for (let i = 0; i < N; i++) {
    while (bitsInBuffer < BITS_PER_COEFF) {
      bitBuffer |= vkBytes[byteIndex++] << bitsInBuffer
      bitsInBuffer += 8
    }
    const coeff = bitBuffer & mask
    bitBuffer >>= BITS_PER_COEFF
    bitsInBuffer -= BITS_PER_COEFF

    if (coeff >= Q) {
      throw new Error(
        `Invalid VK coefficient ${coeff} at index ${i} (must be < ${Q})`,
      )
    }
    coeffs[i] = coeff
  }

  return coeffs
}

// ---------------------------------------------------------------------------
// FalconService
// ---------------------------------------------------------------------------

export class FalconService extends Effect.Service<FalconService>()(
  "FalconService",
  {
    accessors: true,
    // No pre-bundled dependencies: callers must provide WasmRuntime via Layer.
    // This enables unit tests to inject a mock WasmRuntime without the live
    // loader trying to fetch /wasm/falcon_rs.js at import time.
    effect: Effect.gen(function* () {
      const wasm = yield* WasmRuntime

      const generateKeypair = Effect.fn("Falcon.generateKeypair")(
        function* (seed?: Uint8Array) {
          const s =
            seed ?? crypto.getRandomValues(new Uint8Array(32))
          const result = yield* Effect.try({
            try: () => wasm.keygen(s),
            catch: (error) =>
              new KeygenError({ message: String(error) }),
          })
          const publicKeyNtt = yield* Effect.try({
            try: () => parsePublicKeyNttBytes(result.vk),
            catch: (error) =>
              new KeygenError({ message: String(error) }),
          })
          return {
            secretKey: result.sk,
            verifyingKey: result.vk,
            publicKeyNtt,
          } satisfies FalconKeypair
        },
      )

      const sign = Effect.fn("Falcon.sign")(
        function* (
          secretKey: Uint8Array,
          message: Uint8Array,
        ) {
          const result = yield* Effect.try({
            try: () =>
              wasm.sign(secretKey, message, crypto.getRandomValues(new Uint8Array(40))),
            catch: (error) =>
              new SigningError({ message: String(error) }),
          })
          return result satisfies FalconSignatureResult
        },
      )

      const verify = Effect.fn("Falcon.verify")(
        function* (
          verifyingKey: Uint8Array,
          message: Uint8Array,
          signature: Uint8Array,
        ) {
          return yield* Effect.try({
            try: () => wasm.verify(verifyingKey, message, signature),
            catch: (error) =>
              new VerificationError({
                message: String(error),
                step: "verify",
              }),
          })
        },
      )

      const createHint = Effect.fn("Falcon.createHint")(
        function* (
          s1: Int32Array,
          pkNtt: Int32Array,
        ) {
          return yield* Effect.try({
            try: () => wasm.create_verification_hint(s1, pkNtt),
            catch: (error) =>
              new HintGenerationError({ message: String(error) }),
          })
        },
      )

      const packPublicKey = Effect.fn("Falcon.packPublicKey")(
        function* (
          pkNtt: Uint16Array,
        ) {
          const slots = yield* Effect.try({
            try: () => wasm.pack_public_key_wasm(pkNtt),
            catch: (error) =>
              new PackingError({ message: String(error) }),
          })
          return { slots } satisfies PackedPublicKey
        },
      )

      const deserializePublicKeyNtt = Effect.fn(
        "Falcon.deserializePublicKeyNtt",
      )(function* (vkBytes: Uint8Array) {
        return yield* Effect.try({
          try: () => parsePublicKeyNttBytes(vkBytes),
          catch: (error) =>
            new KeygenError({ message: String(error) }),
        })
      })

      return {
        generateKeypair,
        sign,
        verify,
        createHint,
        packPublicKey,
        deserializePublicKeyNtt,
      }
    }),
  },
) {}

"use client"

import { useEffect, useState } from "react"

export type Theme = "dark" | "light"

/** Design-system color tokens for each theme (mirrors globals.css) */
export const THEME_TOKENS = {
  dark: {
    "falcon-bg": "#0f172a",
    "falcon-surface": "#1e293b",
    "falcon-text": "#f8fafc",
    "falcon-muted": "#94a3b8",
  },
  light: {
    "falcon-bg": "#ffffff",
    "falcon-surface": "#f1f5f9",
    "falcon-text": "#0f172a",
    "falcon-muted": "#64748b",
  },
} as const satisfies Record<Theme, Record<string, string>>

/** Brand colors — same across light and dark */
export const BRAND_TOKENS = {
  "falcon-primary": "#6366f1",
  "falcon-secondary": "#8b5cf6",
  "falcon-accent": "#06b6d4",
  "falcon-success": "#10b981",
  "falcon-error": "#ef4444",
} as const satisfies Record<string, string>

/**
 * ThemeToggle — floating button that switches the <html> className
 * between "dark" and "light", triggering Tailwind's class-based dark mode.
 *
 * Defaults to dark (matching the SSR layout.tsx className="dark").
 */
export function ThemeToggle() {
  const [theme, setTheme] = useState<Theme>("dark")

  useEffect(() => {
    document.documentElement.className = theme
  }, [theme])

  const toggle = () => setTheme((prev) => (prev === "dark" ? "light" : "dark"))

  return (
    <button
      onClick={toggle}
      className="fixed top-4 right-4 z-50 rounded-lg border border-falcon-muted/20 bg-falcon-surface p-2 text-sm hover:bg-falcon-surface/80 transition-colors"
      aria-label={theme === "dark" ? "Switch to light mode" : "Switch to dark mode"}
      data-testid="theme-toggle"
      data-theme={theme}
    >
      {theme === "dark" ? "☀️" : "🌙"}
    </button>
  )
}

/**
 * HexDisplay — a client component for rendering hex strings and felt252 arrays.
 *
 * Used in the Verification Playground to show the packed public key slots,
 * salt, and signature preview values. Supports:
 * - Single string values
 * - Arrays of strings with optional `maxRows` clamping
 * - Optional `truncate` prop to shorten long hex values
 */

import React from "react"
import { truncateHex } from "./verification-utils"

export interface HexDisplayProps {
  /** Section label shown above the value(s). */
  readonly label: string
  /** A single hex/felt string, or an array of them. */
  readonly value: string | ReadonlyArray<string>
  /**
   * Maximum number of rows to display when `value` is an array.
   * Excess rows are replaced with a "... N more" indicator.
   */
  readonly maxRows?: number
  /**
   * If provided, each displayed value is truncated to
   * `head` characters + "..." + `tail` characters.
   */
  readonly truncate?: { readonly head: number; readonly tail: number }
}

export function HexDisplay(props: HexDisplayProps): React.JSX.Element {
  const { label, value, maxRows, truncate } = props

  const display = (v: string): string =>
    truncate ? truncateHex(v, truncate.head, truncate.tail) : v

  if (typeof value === "string") {
    return (
      <div>
        <span className="block text-sm font-medium text-falcon-muted">
          {label}
        </span>
        <code className="mt-1 block break-all font-mono text-sm text-falcon-accent">
          {display(value)}
        </code>
      </div>
    )
  }

  const items = Array.from(value)
  const shown = maxRows !== undefined ? items.slice(0, maxRows) : items
  const overflow =
    maxRows !== undefined ? Math.max(0, items.length - maxRows) : 0
  const keyCounts = new Map<string, number>()

  return (
    <div>
      <span className="block text-sm font-medium text-falcon-muted">
        {label}
      </span>
      <div className="mt-1 space-y-0.5">
        {shown.map((v) => {
          const nextCount = (keyCounts.get(v) ?? 0) + 1
          keyCounts.set(v, nextCount)
          const stableKey = nextCount === 1 ? v : `${v}-${nextCount}`
          return (
            <code
              key={stableKey}
              className="block break-all font-mono text-sm text-falcon-accent"
            >
              {display(v)}
            </code>
          )
        })}
        {overflow > 0 && (
          <span className="text-xs text-falcon-muted">
            ... {overflow} more
          </span>
        )}
      </div>
    </div>
  )
}

