import { Schema } from "effect"

// Branded IDs
export const TxHash = Schema.String.pipe(Schema.brand("@Falcon/TxHash"))
export type TxHash = Schema.Schema.Type<typeof TxHash>

export const ContractAddress = Schema.String.pipe(Schema.brand("@Falcon/ContractAddress"))
export type ContractAddress = Schema.Schema.Type<typeof ContractAddress>

// Domain types
export interface FalconKeypair {
  readonly secretKey: Uint8Array
  readonly verifyingKey: Uint8Array
  readonly publicKeyNtt: Int32Array // h polynomial, 512 coefficients
}

export interface FalconSignatureResult {
  readonly signature: Uint8Array
  readonly salt: Uint8Array
}

export interface PackedPublicKey {
  readonly slots: ReadonlyArray<string> // 29 hex strings (felt252)
}

export type VerificationStep =
  | { step: "idle" }
  | { step: "generating-keypair" }
  | { step: "signing" }
  | { step: "creating-hint" }
  | { step: "packing" }
  | { step: "verifying"; substep: string }
  | { step: "complete"; valid: boolean; durationMs: number }
  | { step: "error"; message: string }

export interface PipelineStep {
  readonly id: string
  readonly name: string
  readonly description: string
  readonly input: string
  readonly output: string
  readonly stepCount: number
  readonly status: "pending" | "active" | "complete"
}

import { describe, it, expect } from "bun:test"
import React from "react"
import { renderToStaticMarkup } from "react-dom/server"
import { RegistryProvider } from "@effect-atom/atom-react"
import { Option } from "effect"
import {
  keypairAtom,
  messageAtom,
  verificationStepAtom,
} from "../../atoms/falcon"
import { VerificationPlayground } from "../../components/interactive/VerificationPlayground"
import type { FalconKeypair, VerificationStep } from "../../services/types"

const mockKeypair: FalconKeypair = {
  secretKey: new Uint8Array(1281).fill(1),
  verifyingKey: new Uint8Array(896).fill(2),
  publicKeyNtt: new Int32Array(512).fill(3),
}

function renderPlayground(options?: {
  readonly message?: string
  readonly keypair?: Option.Option<FalconKeypair>
  readonly step?: VerificationStep
}): string {
  const message = options?.message ?? ""
  const keypair = options?.keypair ?? Option.none()
  const step = options?.step ?? { step: "idle" }

  return renderToStaticMarkup(
    React.createElement(
      RegistryProvider,
      {
        initialValues: [
          [messageAtom, message],
          [keypairAtom, keypair],
          [verificationStepAtom, step],
        ],
      },
      React.createElement(VerificationPlayground),
    ),
  )
}

describe("VerificationPlayground", () => {
  it("renders message input and action buttons", () => {
    const html = renderPlayground()

    expect(html).toContain('id="message-input"')
    expect(html).toContain("Generate Keypair")
    expect(html).toContain("Sign &amp; Verify")
  })

  it("adds explicit aria-label attributes to interactive buttons", () => {
    const html = renderPlayground()

    expect(html).toContain('aria-label="Generate Keypair"')
    expect(html).toContain('aria-label="Sign and verify message"')
  })

  it("keeps Sign & Verify disabled without keypair and message", () => {
    const html = renderPlayground()
    const signButton =
      html.match(/<button[^>]*aria-label="Sign and verify message"[^>]*>/)?.[0] ??
      ""

    expect(signButton).toContain('disabled=""')
  })

  it("enables Sign & Verify when keypair and non-empty message are present", () => {
    const html = renderPlayground({
      message: "hello falcon",
      keypair: Option.some(mockKeypair),
    })
    const signButton =
      html.match(/<button[^>]*aria-label="Sign and verify message"[^>]*>/)?.[0] ??
      ""

    expect(signButton).not.toContain('disabled=""')
  })

  it("announces success in a polite live region", () => {
    const html = renderPlayground({
      message: "done",
      keypair: Option.some(mockKeypair),
      step: { step: "complete", valid: true, durationMs: 12 },
    })

    expect(html).toContain('aria-live="polite"')
    expect(html).toContain("Signature valid")
  })

  it("announces errors with alert semantics", () => {
    const html = renderPlayground({
      step: { step: "error", message: "Verification failed" },
    })

    expect(html).toContain('role="alert"')
    expect(html).toContain('aria-live="polite"')
    expect(html).toContain("Verification failed")
  })
})

/**
 * Unit tests for verification utility functions.
 *
 * RED phase: these tests fail until verification-utils.ts is implemented.
 *
 * Coverage:
 * - bytesToHex: browser-safe Uint8Array → hex (no Buffer dependency)
 * - truncateHex: passthrough for short strings, head...tail for long strings
 * - getVerificationDisabledState: disabled-state derivation from atom values
 */

import { describe, it, expect } from "bun:test"
import { Option } from "effect"
import type { FalconKeypair, VerificationStep } from "../../services/types"
import {
  bytesToHex,
  truncateHex,
  getVerificationDisabledState,
} from "../../components/interactive/verification-utils"

// ─── bytesToHex ──────────────────────────────────────────────────────────────

describe("bytesToHex", () => {
  it("converts empty Uint8Array to empty string", () => {
    expect(bytesToHex(new Uint8Array(0))).toBe("")
  })

  it("converts single byte 0xff to 'ff'", () => {
    expect(bytesToHex(new Uint8Array([0xff]))).toBe("ff")
  })

  it("converts single byte 0x00 to '00'", () => {
    expect(bytesToHex(new Uint8Array([0x00]))).toBe("00")
  })

  it("converts multiple bytes to lowercase hex string", () => {
    expect(bytesToHex(new Uint8Array([0x01, 0xab, 0xcd]))).toBe("01abcd")
  })

  it("is browser-safe — no Buffer dependency (dead beef test)", () => {
    const bytes = new Uint8Array([0xde, 0xad, 0xbe, 0xef])
    expect(bytesToHex(bytes)).toBe("deadbeef")
  })

  it("pads single-hex-digit bytes with leading zero", () => {
    const bytes = new Uint8Array([0x0f, 0x10])
    expect(bytesToHex(bytes)).toBe("0f10")
  })
})

// ─── truncateHex ─────────────────────────────────────────────────────────────

describe("truncateHex", () => {
  it("returns unchanged string when shorter than head+tail+3", () => {
    // "0x1234" = 6 chars; head=4, tail=4 → threshold=11 → don't truncate
    expect(truncateHex("0x1234", 4, 4)).toBe("0x1234")
  })

  it("returns unchanged empty string", () => {
    expect(truncateHex("", 4, 4)).toBe("")
  })

  it("returns unchanged string at exact threshold boundary", () => {
    // "12345678" = 8 chars; head=4, tail=4 → threshold=11 → 8<=11 → don't truncate
    expect(truncateHex("12345678", 4, 4)).toBe("12345678")
  })

  it("truncates a long hex string to head...tail format", () => {
    const long = "0x" + "a".repeat(64) // 66 chars
    const result = truncateHex(long, 6, 4)
    expect(result).toContain("...")
    // First 6 chars of long = "0xaaaa" (2 + 4)
    expect(result.startsWith("0x" + "a".repeat(4))).toBe(true)
    // Last 4 chars = "aaaa"
    expect(result.endsWith("a".repeat(4))).toBe(true)
  })

  it("truncated result has format <head>...<tail>", () => {
    const value = "1234567890abcdef" // 16 chars
    const result = truncateHex(value, 4, 4) // threshold=11, 16>11 → truncate
    expect(result).toBe("1234...cdef")
  })

  it("uses exactly three dots as separator", () => {
    const long = "x".repeat(20)
    const result = truncateHex(long, 4, 4)
    const dotIndex = result.indexOf("...")
    expect(dotIndex).toBeGreaterThan(-1)
    // Only one occurrence of "..."
    expect(result.indexOf("...", dotIndex + 3)).toBe(-1)
  })
})

// ─── getVerificationDisabledState ────────────────────────────────────────────

const mockKeypair: FalconKeypair = {
  secretKey: new Uint8Array(1281),
  verifyingKey: new Uint8Array(896),
  publicKeyNtt: new Int32Array(512),
}

describe("getVerificationDisabledState", () => {
  it("canSign=false when keypair is Option.none()", () => {
    const result = getVerificationDisabledState({
      keypair: Option.none(),
      message: "hello",
      step: { step: "idle" },
    })
    expect(result.canSign).toBe(false)
  })

  it("canSign=false when message is empty string", () => {
    const result = getVerificationDisabledState({
      keypair: Option.some(mockKeypair),
      message: "",
      step: { step: "idle" },
    })
    expect(result.canSign).toBe(false)
  })

  it("canSign=false when message is whitespace only", () => {
    const result = getVerificationDisabledState({
      keypair: Option.some(mockKeypair),
      message: "   ",
      step: { step: "idle" },
    })
    expect(result.canSign).toBe(false)
  })

  it("canSign=true when keypair exists, message non-empty, and step is idle", () => {
    const result = getVerificationDisabledState({
      keypair: Option.some(mockKeypair),
      message: "test message",
      step: { step: "idle" },
    })
    expect(result.canSign).toBe(true)
  })

  it("isBusy=true and both buttons disabled while signing", () => {
    const result = getVerificationDisabledState({
      keypair: Option.some(mockKeypair),
      message: "test",
      step: { step: "signing" },
    })
    expect(result.isBusy).toBe(true)
    expect(result.canGenerate).toBe(false)
    expect(result.canSign).toBe(false)
  })

  it("isBusy=true and both buttons disabled while generating-keypair", () => {
    const result = getVerificationDisabledState({
      keypair: Option.none(),
      message: "",
      step: { step: "generating-keypair" },
    })
    expect(result.isBusy).toBe(true)
    expect(result.canGenerate).toBe(false)
    expect(result.canSign).toBe(false)
  })

  it("isBusy=true while creating-hint", () => {
    const result = getVerificationDisabledState({
      keypair: Option.some(mockKeypair),
      message: "test",
      step: { step: "creating-hint" },
    })
    expect(result.isBusy).toBe(true)
  })

  it("isBusy=true while packing", () => {
    const result = getVerificationDisabledState({
      keypair: Option.some(mockKeypair),
      message: "test",
      step: { step: "packing" },
    })
    expect(result.isBusy).toBe(true)
  })

  it("isBusy=true while verifying", () => {
    const result = getVerificationDisabledState({
      keypair: Option.some(mockKeypair),
      message: "test",
      step: { step: "verifying", substep: "ntt" },
    })
    expect(result.isBusy).toBe(true)
  })

  it("canGenerate=true when idle", () => {
    const result = getVerificationDisabledState({
      keypair: Option.none(),
      message: "",
      step: { step: "idle" },
    })
    expect(result.canGenerate).toBe(true)
    expect(result.isBusy).toBe(false)
  })

  it("isBusy=false and canGenerate=true after complete (terminal state)", () => {
    const result = getVerificationDisabledState({
      keypair: Option.some(mockKeypair),
      message: "test",
      step: { step: "complete", valid: true, durationMs: 42 },
    })
    expect(result.isBusy).toBe(false)
    expect(result.canGenerate).toBe(true)
  })

  it("isBusy=false after error (terminal state)", () => {
    const result = getVerificationDisabledState({
      keypair: Option.some(mockKeypair),
      message: "test",
      step: { step: "error", message: "boom" },
    })
    expect(result.isBusy).toBe(false)
    expect(result.canGenerate).toBe(true)
  })
})

import { Config, Effect } from "effect"
import { RpcProvider, Account, hash, CallData, stark } from "starknet"
import {
  StarknetRpcError,
  AccountDeployError,
} from "./errors"
import { TxHash, ContractAddress } from "./types"
import type { PackedPublicKey } from "./types"

// FalconAccount class hash — must be declared on mainnet first
const FALCON_ACCOUNT_CLASS_HASH = "0x0" // TODO: replace after declaring

/** STRK token contract address on Starknet mainnet */
export const STRK_TOKEN_ADDRESS =
  "REDACTED"

export class StarknetService extends Effect.Service<StarknetService>()(
  "StarknetService",
  {
    accessors: true,
    effect: Effect.gen(function* () {
      const rpcUrl = yield* Config.string("NEXT_PUBLIC_STARKNET_RPC_URL")
      const provider = new RpcProvider({ nodeUrl: rpcUrl })

      const computeDeployAddress = Effect.fn("Starknet.computeDeployAddress")(
        function* (packedPk: PackedPublicKey) {
          const constructorCalldata = CallData.compile({
            pk_packed: packedPk.slots,
          })
          const salt = stark.randomAddress()
          const address = hash.calculateContractAddressFromHash(
            salt,
            FALCON_ACCOUNT_CLASS_HASH,
            constructorCalldata,
            0,
          )
          return ContractAddress.make(address)
        },
      )

      const getBalance = Effect.fn("Starknet.getBalance")(
        function* (address: string) {
          return yield* Effect.tryPromise({
            try: async () => {
              const result = await provider.callContract({
                contractAddress: STRK_TOKEN_ADDRESS,
                entrypoint: "balanceOf",
                calldata: [address],
              })
              return BigInt(result[0])
            },
            catch: (error) =>
              new StarknetRpcError({ message: String(error), code: -1 }),
          })
        },
      )

      const deployAccount = Effect.fn("Starknet.deployAccount")(
        function* (packedPk: PackedPublicKey, privateKey: string) {
          const constructorCalldata = CallData.compile({
            pk_packed: packedPk.slots,
          })
          const salt = stark.randomAddress()
          const address = hash.calculateContractAddressFromHash(
            salt,
            FALCON_ACCOUNT_CLASS_HASH,
            constructorCalldata,
            0,
          )

          // starknet v9 Account constructor takes a single AccountOptions object
          const account = new Account({ provider, address, signer: privateKey })

          const result = yield* Effect.tryPromise({
            try: () =>
              account.deployAccount({
                classHash: FALCON_ACCOUNT_CLASS_HASH,
                constructorCalldata,
                addressSalt: salt,
                contractAddress: address,
              }),
            catch: (error) =>
              new AccountDeployError({ message: String(error) }),
          })

          yield* Effect.tryPromise({
            try: () => provider.waitForTransaction(result.transaction_hash),
            catch: (error) =>
              new AccountDeployError({
                message: `Tx failed: ${error}`,
                txHash: result.transaction_hash,
              }),
          })

          return {
            txHash: TxHash.make(result.transaction_hash),
            address: ContractAddress.make(result.contract_address),
          }
        },
      )

      const waitForTx = Effect.fn("Starknet.waitForTx")(
        function* (txHash: string) {
          yield* Effect.tryPromise({
            try: () => provider.waitForTransaction(txHash),
            catch: (error) =>
              new StarknetRpcError({ message: String(error), code: -1 }),
          })
        },
      )

      return {
        computeDeployAddress,
        getBalance,
        deployAccount,
        waitForTx,
        provider,
      }
    }),
  },
) {}

import { Schema } from "effect"

export class WasmLoadError extends Schema.TaggedError<WasmLoadError>()(
  "WasmLoadError",
  { message: Schema.String },
) {}

export class KeygenError extends Schema.TaggedError<KeygenError>()(
  "KeygenError",
  { message: Schema.String },
) {}

export class SigningError extends Schema.TaggedError<SigningError>()(
  "SigningError",
  { message: Schema.String },
) {}

export class VerificationError extends Schema.TaggedError<VerificationError>()(
  "VerificationError",
  { message: Schema.String, step: Schema.String },
) {}

export class HintGenerationError extends Schema.TaggedError<HintGenerationError>()(
  "HintGenerationError",
  { message: Schema.String },
) {}

export class PackingError extends Schema.TaggedError<PackingError>()(
  "PackingError",
  { message: Schema.String },
) {}

export class StarknetRpcError extends Schema.TaggedError<StarknetRpcError>()(
  "StarknetRpcError",
  { message: Schema.String, code: Schema.Number },
) {}

export class AccountDeployError extends Schema.TaggedError<AccountDeployError>()(
  "AccountDeployError",
  { message: Schema.String, txHash: Schema.optional(Schema.String) },
) {}

export class InsufficientFundsError extends Schema.TaggedError<InsufficientFundsError>()(
  "InsufficientFundsError",
  { message: Schema.String, address: Schema.String, required: Schema.String },
) {}

import { Effect, Option, Schema } from "effect"
import { FalconService } from "@/services/FalconService"
import { StarknetService } from "@/services/StarknetService"
import { InsufficientFundsError } from "@/services/errors"
import type {
  ContractAddress,
  FalconKeypair,
  PackedPublicKey,
} from "@/services/types"

const FALCON_PUBLIC_KEY_LENGTH = 512
const FALCON_MODULUS = 12289

export class InvalidPrivateKeyError extends Schema.TaggedError<InvalidPrivateKeyError>()(
  "InvalidPrivateKeyError",
  { message: Schema.String },
) {}

export class InvalidPublicKeyNttError extends Schema.TaggedError<InvalidPublicKeyNttError>()(
  "InvalidPublicKeyNttError",
  { message: Schema.String },
) {}

export interface PreparedAccountDeploy {
  readonly privateKey: string
  readonly keypair: FalconKeypair
  readonly packedPublicKey: PackedPublicKey
  readonly address: ContractAddress
}

export interface DeployAccountInput {
  readonly address: ContractAddress
  readonly packedPublicKey: PackedPublicKey
  readonly privateKey: string
  readonly requiredBalance: bigint
}

export const validateHexPrivateKey = Effect.fn(
  "AccountDeployPipeline.validateHexPrivateKey",
)((privateKey: string) =>
  Effect.try({
    try: () => {
      const trimmed = privateKey.trim()
      const normalized = trimmed.toLowerCase()

      if (!normalized.startsWith("0x")) {
        throw new Error("Private key must be 0x-prefixed")
      }

      const hexBody = normalized.slice(2)
      if (hexBody.length !== 64) {
        throw new Error("Private key must be a 32-byte hex string")
      }

      if (!/^[0-9a-f]+$/u.test(hexBody)) {
        throw new Error("Private key contains non-hex characters")
      }

      return normalized
    },
    catch: (error) =>
      new InvalidPrivateKeyError({
        message: String(error),
      }),
  }),
)

export const toUint16PublicKeyNtt = Effect.fn(
  "AccountDeployPipeline.toUint16PublicKeyNtt",
)((publicKeyNtt: Int32Array) =>
  Effect.try({
    try: () => {
      if (publicKeyNtt.length !== FALCON_PUBLIC_KEY_LENGTH) {
        throw new Error(
          `publicKeyNtt must have ${FALCON_PUBLIC_KEY_LENGTH} coefficients`,
        )
      }

      const packed = new Uint16Array(FALCON_PUBLIC_KEY_LENGTH)
      for (let i = 0; i < publicKeyNtt.length; i += 1) {
        const coeff = publicKeyNtt[i]
        if (coeff < 0 || coeff >= FALCON_MODULUS) {
          throw new Error(`publicKeyNtt coefficient out of range at index ${i}`)
        }
        packed[i] = coeff
      }

      return packed
    },
    catch: (error) =>
      new InvalidPublicKeyNttError({
        message: String(error),
      }),
  }),
)

interface PrepareAccountDeployInput {
  readonly privateKey: string
  readonly existingKeypair: Option.Option<FalconKeypair>
}

export const prepareAccountDeployEffect = Effect.fn(
  "AccountDeployPipeline.prepareAccountDeployEffect",
)(function* ({ privateKey, existingKeypair }: PrepareAccountDeployInput) {
  const normalizedPrivateKey = yield* validateHexPrivateKey(privateKey)

  const keypair = yield* Option.match(existingKeypair, {
    onNone: () => FalconService.generateKeypair(),
    onSome: (currentKeypair) => Effect.succeed(currentKeypair),
  })

  const publicKeyNtt = yield* toUint16PublicKeyNtt(keypair.publicKeyNtt)
  const packedPublicKey = yield* FalconService.packPublicKey(publicKeyNtt)
  const address = yield* StarknetService.computeDeployAddress(packedPublicKey)

  return {
    privateKey: normalizedPrivateKey,
    keypair,
    packedPublicKey,
    address,
  } satisfies PreparedAccountDeploy
})

export const deployAccountEffect = Effect.fn(
  "AccountDeployPipeline.deployAccountEffect",
)(function* ({
  address,
  packedPublicKey,
  privateKey,
  requiredBalance,
}: DeployAccountInput) {
  const normalizedPrivateKey = yield* validateHexPrivateKey(privateKey)
  const balance = yield* StarknetService.getBalance(address)

  if (balance < requiredBalance) {
    return yield* Effect.fail(
      new InsufficientFundsError({
        message: "Insufficient STRK balance. Fund the account and try again.",
        address,
        required: requiredBalance.toString(),
      }),
    )
  }

  const deployment = yield* StarknetService.deployAccount(
    packedPublicKey,
    normalizedPrivateKey,
  )

  return deployment
})

import { Atom } from "@effect-atom/atom"
import { Option } from "effect"
import type { FalconKeypair, FalconSignatureResult, VerificationStep } from "../services/types"

export const wasmStatusAtom = Atom.make<"loading" | "ready" | "error">("loading").pipe(
